const platformPackage = $json.platform_package_packet || { payload: { metadata: {} } };
const scriptSections = $json.final_script_packet?.payload?.sections || [{ title: 'main', content: 'content summary' }];
const assetBrief = {
  thumbnail_brief: { variants: 3, direction: 'Create 3 visual concepts representing key themes from the content', elements: ['hook_visual', 'text_overlay', 'color_palette'] },
  broll_cues: scriptSections.map((s, i) => ({ section: s.title, timestamp: i * 30, visual_direction: 'supporting_visuals_for_' + s.title, estimated_duration: '10-20_seconds' })),
  caption_brief: { language: 'en', requirements: ['speaker_identification', 'sound_effects_noted', 'emphasis_markers'], style: 'professional' },
  audio_brief: { voiceover_style: 'clear_and_engaging', pacing: 'conversational', music_cues: ['intro_upbeat', 'transitions_smooth', 'outro_resolution'], sound_design: 'minimal_enhancement' }
};
return [{ json: { ...$json, asset_brief: assetBrief, asset_brief_ready: true } }];

const packet = {
  instance_id: 'BRIEF-' + Date.now(),
  artifact_family: 'asset_brief_packet',
  schema_version: '1.0.0',
  producer_workflow: 'CWF-330',
  dossier_ref: $json.dossier_id || 'DOSSIER-UNSPECIFIED',
  created_at: new Date().toISOString(),
  status: 'CREATED',
  payload: {
    asset_brief_ready: true,
    thumbnail_brief: $json.asset_brief.thumbnail_brief,
    broll_cues: $json.asset_brief.broll_cues,
    caption_brief: $json.asset_brief.caption_brief,
    audio_brief: $json.asset_brief.audio_brief,
    total_sections: $json.asset_brief.broll_cues.length
  }
};
return [{ json: { ...$json, asset_brief_packet: packet, packet_emitted: true } }];

try {
  const SkillLoader = require('../../../engine/skill_loader/skill_loader.js');
  const loader = new SkillLoader();

  if (!loader.skills_registry || Object.keys(loader.skills_registry).length === 0) {
    const initResult = await loader.initialize();
    if (initResult.status !== 'initialized') {
      throw new Error('Failed to initialize SkillLoader');
    }
  }

  const workflowId = 'CWF-330';
  const defaultSkillMap = {"CWF-310":"M-001","CWF-320":"M-001","CWF-330":"M-001","CWF-340":"M-001","CWF-410":"M-001","CWF-420":"M-001","CWF-430":"M-001","CWF-440":"M-001","CWF-510":"M-001","CWF-520":"M-001","CWF-530":"M-001"};
  const skillId = $json.skill_id || defaultSkillMap[workflowId] || 'M-001';
  const dossierId = $json.dossier_context?.dossier_id || $json.dossier_id || 'DOSSIER-UNSPECIFIED';

  const contextPacket = {
    dossier_id: dossierId,
    workflow_id: workflowId,
    ...(typeof $json.user_context === 'object' ? $json.user_context : {}),
    ...(typeof $json.route_context === 'object' ? $json.route_context : {})
  };

  const dossierState = typeof $json.dossier === 'object' ? $json.dossier : {};
  const result = await loader.executeSkill(skillId, contextPacket, dossierState);

  return [{
    json: {
      ...$json,
      phase8_runtime_probe: {
        workflow_id: workflowId,
        skill_id: skillId,
        status: result.status,
        had_error: result.status !== 'SUCCESS',
        error_message: result.status === 'SUCCESS' ? '' : String(result.error || ''),
        timestamp: new Date().toISOString()
      },
      runtime_packet: result.status === 'SUCCESS' ? (result.output || null) : null,
      skill_execution_result: result.status === 'SUCCESS' ? result : null,
      runtime: {
        had_error: result.status !== 'SUCCESS',
        error_message: result.status === 'SUCCESS' ? '' : String(result.error || '')
      }
    }
  }];
} catch (error) {
  const message = String(error && error.message ? error.message : error);
  return [{
    json: {
      ...$json,
      phase8_runtime_probe: {
        workflow_id: 'CWF-330',
        skill_id: null,
        status: 'ERROR',
        had_error: true,
        error_message: message,
        timestamp: new Date().toISOString()
      },
      runtime_packet: null,
      skill_execution_result: null,
      runtime: { had_error: true, error_message: message }
    }
  }];
}
